export interface ViewportSize {
  width: number;
  height: number;
}

export const getViewportSize = (): ViewportSize => {
  const { document: doc } = window;
  const { body, documentElement } = doc;
  const { clientWidth, clientHeight } = documentElement;
  const width = (doc.compatMode === 'CSS1Compat' && clientWidth) || (body && body.clientWidth) || clientWidth;
  const height = (doc.compatMode === 'CSS1Compat' && clientHeight) || (body && body.clientHeight) || clientHeight;

  return {
    width,
    height,
  };
};
